/*
  Format Error Payload — isolates 4 sources into common format.
  - Error Trigger: { execution, workflow }
  - Webhook / Execute / Manual: manual payload
*/
const incoming = $input.first()?.json || {};
const isSystemError = !!incoming.execution;
const payload = isSystemError ? incoming : incoming.body || incoming;

return {
  workflow_id: payload.workflow?.id || "UNKNOWN",
  workflow_name: payload.workflow?.name || "UNKNOWN",
  execution_id: payload.execution?.id || "MANUAL_TEST_ID",
  error_message: payload.execution?.error?.message || payload.error_message || "Unknown Error",
  error_stack: payload.execution?.error?.stack || "",
  last_node: payload.execution?.lastNodeExecuted || "",
  mode: payload.execution?.mode || "manual"
};

// VRF — Build Safe SQL (SEC_02: escape backslash + single quote + length limit)
const esc = (v) => String(v || '').replace(/\\/g, '\\\\').replace(/'/g, "''").substring(0, 500);
const data = $input.first()?.json || {};

const wfName = esc(data.workflow_name);
const execId = esc(data.execution_id);
const errMsg = esc(data.error_message);
const details = esc(JSON.stringify(data));

return [{
  json: {
    query: `INSERT INTO system_logs (workflow_name, execution_id, level, message, details) VALUES ('${wfName}', '${execId}', 'ERROR', '${errMsg}', '${details}') RETURNING id;`,
    ...data
  }
}];

